// Minimal human-readable ABI for the MembershipVoucher (spec 026). The full JSON ABI is generated by
// `npm run sync:frontend-contracts` at deploy; this hand-authored fragment covers the surface the UI uses.
export const MEMBERSHIP_VOUCHER_ABI = [
  'function mint(bytes32 role, uint8 tier) returns (uint256 id)',
  'function voucherInfo(uint256 tokenId) view returns (tuple(bytes32 role, uint8 tier, uint32 durationDays))',
  'function ownerOf(uint256 tokenId) view returns (address)',
  'function tokenURI(uint256 tokenId) view returns (string)',
  'function royaltyInfo(uint256 tokenId, uint256 salePrice) view returns (address, uint256)',
  'function royaltyBps() view returns (uint96)',
  'function transferFrom(address from, address to, uint256 tokenId)',
  'event VoucherMinted(uint256 indexed id, address indexed minter, bytes32 indexed role, uint8 tier, uint32 durationDays, uint128 priceUSDC)',
]

// Redemption + tier-price read live on the MembershipManager proxy (spec 026 ships as its first upgrade).
export const MEMBERSHIP_VOUCHER_REDEEM_ABI = [
  'function redeemVoucher(uint256 voucherId, bytes32 acceptedTermsHash)',
  'function voucher() view returns (address)',
  'function hasActiveRole(address user, bytes32 role) view returns (bool)',
  'function getTierConfig(bytes32 role, uint8 tier) view returns (tuple(uint128 priceUSDC, uint32 durationDays, bool active, tuple(uint32 monthlyMarketCreation, uint32 maxConcurrentMarkets) limits))',
]
